const hoje = new Date().toISOString().split('T')[0]; // YYYY-MM-DD
const yesterday = new Date(Date.now() - 86400000).toISOString();
return [{ json: { hoje, yesterday } }];

const tweets = $input.first().json?.data || [];
const filtered = tweets
  .filter(t => t.public_metrics?.like_count >= 100)
  .sort((a, b) => b.public_metrics.like_count - a.public_metrics.like_count)
  .slice(0, 5)
  .map(t => ({ text: t.text, likes: t.public_metrics.like_count, source: 'twitter_pt' }));
return [{ json: { tweets_pt: filtered } }];

const tweets = $input.first().json?.data || [];
const filtered = tweets
  .filter(t => t.public_metrics?.like_count >= 200)
  .slice(0, 3)
  .map(t => ({ text: t.text, likes: t.public_metrics.like_count, source: 'attia' }));
return [{ json: { tweets_attia: filtered } }];

const tweets = $input.first().json?.data || [];
const filtered = tweets
  .filter(t => t.public_metrics?.like_count >= 500)
  .slice(0, 3)
  .map(t => ({ text: t.text, likes: t.public_metrics.like_count, source: 'huberman' }));
return [{ json: { tweets_huberman: filtered } }];

// Parse RSS items - n8n XML node returns parsed structure
const channel = $input.first().json?.rss?.channel || {};
const items = Array.isArray(channel.item) ? channel.item : (channel.item ? [channel.item] : []);
const parsed = items.slice(0, 5).map(item => ({
  title: item.title || '',
  abstract: (item.description || '').replace(/<[^>]*>/g, '').substring(0, 400),
  url: item.link || '',
  source: 'pubmed'
}));
return [{ json: { pubmed: parsed } }];

// Collect all items from different branches
const allItems = $input.all();
let tweets_pt = [], tweets_attia = [], tweets_huberman = [], pubmed = [];

for (const item of allItems) {
  if (item.json.tweets_pt) tweets_pt = item.json.tweets_pt;
  if (item.json.tweets_attia) tweets_attia = item.json.tweets_attia;
  if (item.json.tweets_huberman) tweets_huberman = item.json.tweets_huberman;
  if (item.json.pubmed) pubmed = item.json.pubmed;
}

const hoje = new Date().toLocaleDateString('pt-BR');

let context = `## TWITTER PT-BR (top ${tweets_pt.length} por likes)\n`;
tweets_pt.forEach((t, i) => { context += `${i+1}. [${t.likes} likes]: ${t.text}\n`; });

context += `\n## ATTIA (\u00faltimas 24h)\n`;
tweets_attia.forEach((t, i) => { context += `${i+1}. [${t.likes} likes]: ${t.text}\n`; });

context += `\n## HUBERMAN (\u00faltimas 24h)\n`;
tweets_huberman.forEach((t, i) => { context += `${i+1}. [${t.likes} likes]: ${t.text}\n`; });

context += `\n## PUBMED (recentes)\n`;
pubmed.forEach((t, i) => { context += `${i+1}. ${t.title}\n   ${t.abstract}\n   URL: ${t.url}\n`; });

context += `\n## DATA\nHoje: ${hoje}`;

return [{ json: { context, hoje: new Date().toISOString().split('T')[0] } }];

const responseText = $input.first().json.content[0].text;
let drafts;
try {
  // Handle case where Claude wraps in markdown code blocks
  const cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  drafts = JSON.parse(cleaned).drafts;
} catch(e) {
  // Fallback: extract JSON manually
  const match = responseText.match(/\{[\s\S]*\}/);
  if (match) {
    drafts = JSON.parse(match[0]).drafts;
  } else {
    throw new Error('Could not parse Claude response: ' + responseText.substring(0, 200));
  }
}
return [{ json: { drafts, context: $('Build Context').item.json.context, hoje: $('Build Context').item.json.hoje } }];

const { drafts, context, hoje } = $input.first().json;
const validated = drafts.map(d => {
  const count = d.texto.length;
  const flag = count > 280 ? '\u26a0\ufe0f ' : '';
  return {
    ...d,
    texto: count > 280 ? d.texto.substring(0, 277) + '...' : d.texto,
    char_count: Math.min(count, 280),
    char_flag: flag
  };
});
return [{ json: { drafts: validated, context, hoje } }];

const { drafts, hoje } = $input.first().json;
const data = new Date().toLocaleDateString('pt-BR');

let msg = `\ud83d\udc26 *TWEETS DO DIA \u2014 ${data}*\n\n`;

drafts.forEach((d, i) => {
  msg += `\u2501\u2501\u2501 TWEET ${d.id} (${d.horario_sugerido}) \u2014 ${d.format} \u2501\u2501\u2501\n`;
  msg += `${d.char_flag}${d.texto}\n`;
  msg += `\ud83d\udcca ${d.char_count} chars | Fonte: ${d.fonte}\n\n`;
});

msg += `---\n\u2705 aprova \\[1,2,3\\]  |  \u270f\ufe0f edita N: \\[texto\\]  |  \u274c ignore`;

return [{ json: { message: msg, drafts: $input.first().json.drafts, context: $input.first().json.context, hoje } }];
